import{_ as a,o as n,c as t,a3 as l}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"16. Educational Incentive Allowance","description":"","frontmatter":{"title":"16. Educational Incentive Allowance","eba":"Health Allied & Managers Admin 2021-2025","topics":["allowances","employment","education-pd"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/allowances/16-educational-incentive-allowance.md","filePath":"ebas/has-managers-admin/health-allied-services/allowances/16-educational-incentive-allowance.md"}'),o={name:"ebas/has-managers-admin/health-allied-services/allowances/16-educational-incentive-allowance.md"};function i(s,e,r,c,d,p){return n(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="_16-educational-incentive-allowance" tabindex="-1">16. Educational Incentive Allowance <a class="header-anchor" href="#_16-educational-incentive-allowance" aria-label="Permalink to &quot;16. Educational Incentive Allowance&quot;">​</a></h1><p>This clause does not apply to casual Employees</p><p><strong>16.1</strong> All full-time Eligible Employees who were employed as at 13 May 2021 will receive an Educational Incentive Allowance of $500, payable in a single amount from the FFPPOA the operative date of this Agreement.</p><p><strong>16.2</strong> In 2022 and each year thereafter, all full-time Eligible Employees will receive an annual Educational Incentive allowance of $500, payable in two instalments of $250 as follows: Amount Date $250 FFPPOA 31 March 2022 $250 FFPPOA 30 September 2022 $250 FFPPOA 31 March 2023 $250 FFPPOA 30 September 2023 $250 FFPPOA 31 March 2024 $250 FFPPOA 30 September 2024</p><p><strong>16.3</strong> The allowances at clause 0 and 16.2 will be paid pro rata for Part-time Employees.</p><p><strong>16.4</strong> The Educational Incentive Allowance will be payable in respect of a particular year to any Eligible Employee who is employed by an Employer (and not on unpaid leave) on the date that the payment is due as provided in subclause 0 and 16.2 above.</p><p><strong>16.5</strong> The allowance is paid to encourage Eligible Employees who have not had the opportunity to participate in any professional development and education, to enable career progression in classifications that are highly susceptible to automation.</p><p><strong>16.6</strong> Such payment is to facilitate access by eligible Employees to courses, conferences and seminars which will result in the development of skills and knowledge and is in addition to any other entitlement under the Study Leave clause.</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>16.7</strong> Eligible Employees for the purpose of this clause 16 will be Employees employed within the following classifications: Cook Grade 1 Allied Health Assistant Grade 1 Food and Domestic Assistant Grade 2 Anaesthetic Technician Grade 1 Car Park Attendant Grade 2 Health Care Worker Grade 1 Cleaner/Patient Transport Office Grade 2 Instrument Technician Grade 1 Driver &lt;1.25 tonnes Laboratory Assistant Grade 1 (more than 3 months experience) Gardener (Non-Trade) Leisure and Lifestyle Assistant Grade 1 Handyperson (Unqual) (more than 3 Pathology Collector Grade 1 months experience) Laundry Hand Grade 2 Pathology Technician Grade 1 Patient Services Assistant Level 1 Pharmacy Technician Grade 1 Storeperson Alone Theatre Technician Grade 1</p><p>Plain language terms: qualifications allowance.</p>',11)])])}const u=a(o,[["render",i]]);export{m as __pageData,u as default};
